# feature_flags.py
# Lightweight feature flag client for GenAI integration code
# Integrates with LaunchDarkly, but the interface is provider-agnostic
# so you can swap to Unleash, Split, or a static config file for tests.

import os
import hashlib
from dataclasses import dataclass
from typing import Optional, Any

try:
    import ldclient
    from ldclient.config import Config as LDConfig
    _HAS_LD = True
except ImportError:
    _HAS_LD = False


@dataclass
class FlagContext:
    user_id: str
    account_id: Optional[str] = None
    region: Optional[str] = None
    environment: str = "production"   # production | staging | internal


class GenAIFlags:
    # All GenAI feature flag keys in one place.
    # Adding a new flag: define the key here, add a default below,
    # and add it to the flag audit table in the wiki.

    NEW_AGENT_V2     = "genai.new-agent-v2"
    PROMPT_V2_EXP    = "genai.prompt-v2-experiment"
    TOOL_V2_BETA     = "genai.tool-call-v2-beta"
    SAFETY_V3        = "genai.safety-filter-v3"
    STREAMING_OUTPUT = "genai.streaming-output"
    CACHE_PROMPTS    = "genai.prompt-caching-enabled"

    # Default values used when the flag service is unreachable.
    # Defaults must be the SAFE fallback (usually the old behaviour).
    DEFAULTS = {
        NEW_AGENT_V2:     False,
        PROMPT_V2_EXP:    False,
        TOOL_V2_BETA:     False,
        SAFETY_V3:        False,
        STREAMING_OUTPUT: False,
        CACHE_PROMPTS:    False,
    }


class FlagClient:
    def __init__(self, sdk_key: Optional[str] = None, offline: bool = False):
        self._offline = offline or not _HAS_LD
        if not self._offline:
            sdk_key = sdk_key or os.environ.get("LAUNCHDARKLY_SDK_KEY")
            if not sdk_key:
                raise ValueError("LAUNCHDARKLY_SDK_KEY env var is required unless offline=True")
            ldclient.set_config(LDConfig(sdk_key))
            self._ld = ldclient.get()
        else:
            self._ld = None
        # Override map for tests: flag_key -> value
        self._overrides: dict[str, Any] = {}

    def override(self, flag_key: str, value: Any) -> None:
        # Use in tests only. Overrides take precedence over LD and defaults.
        self._overrides[flag_key] = value

    def clear_overrides(self) -> None:
        self._overrides.clear()

    def is_enabled(self, flag_key: str, ctx: FlagContext) -> bool:
        if flag_key in self._overrides:
            return bool(self._overrides[flag_key])
        if self._offline:
            return bool(GenAIFlags.DEFAULTS.get(flag_key, False))
        ld_user = {
            "key": ctx.user_id,
            "custom": {
                "account_id": ctx.account_id or "",
                "region": ctx.region or "",
                "environment": ctx.environment,
            }
        }
        return self._ld.variation(
            flag_key,
            ld_user,
            GenAIFlags.DEFAULTS.get(flag_key, False)
        )

    def get_string(self, flag_key: str, ctx: FlagContext, default: str = "") -> str:
        if flag_key in self._overrides:
            return str(self._overrides[flag_key])
        if self._offline:
            return default
        ld_user = {"key": ctx.user_id}
        return self._ld.variation(flag_key, ld_user, default)

    def close(self) -> None:
        if self._ld:
            self._ld.close()


# Module-level singleton — import this in production code
_client: Optional[FlagClient] = None

def get_flag_client() -> FlagClient:
    global _client
    if _client is None:
        _client = FlagClient()
    return _client


