# test_feature_flags.py
# Test suite for GenAI feature flag integration
# Run: pytest test_feature_flags.py -v

import pytest
from feature_flags import FlagClient, FlagContext, GenAIFlags


@pytest.fixture
def flags():
    # Offline mode: returns defaults, no network required
    client = FlagClient(offline=True)
    yield client
    client.clear_overrides()


@pytest.fixture
def ctx():
    return FlagContext(user_id="test-user-001", environment="test")


class TestDefaults:
    def test_new_agent_v2_defaults_off(self, flags, ctx):
        assert flags.is_enabled(GenAIFlags.NEW_AGENT_V2, ctx) is False

    def test_all_genai_flags_default_to_safe_value(self, flags, ctx):
        for key, default in GenAIFlags.DEFAULTS.items():
            result = flags.is_enabled(key, ctx)
            assert result == bool(default), f"Flag {key} default mismatch"


class TestOverrides:
    def test_override_enables_flag(self, flags, ctx):
        flags.override(GenAIFlags.NEW_AGENT_V2, True)
        assert flags.is_enabled(GenAIFlags.NEW_AGENT_V2, ctx) is True

    def test_override_disables_flag(self, flags, ctx):
        flags.override(GenAIFlags.SAFETY_V3, False)
        assert flags.is_enabled(GenAIFlags.SAFETY_V3, ctx) is False

    def test_clear_overrides_restores_default(self, flags, ctx):
        flags.override(GenAIFlags.NEW_AGENT_V2, True)
        flags.clear_overrides()
        assert flags.is_enabled(GenAIFlags.NEW_AGENT_V2, ctx) is False

    def test_override_does_not_affect_other_flags(self, flags, ctx):
        flags.override(GenAIFlags.NEW_AGENT_V2, True)
        # Safety flag should remain at its own default
        assert flags.is_enabled(GenAIFlags.SAFETY_V3, ctx) == bool(GenAIFlags.DEFAULTS[GenAIFlags.SAFETY_V3])


class TestFlagIsolation:
    def test_two_users_can_have_different_flag_values_via_override(self, ctx):
        client_a = FlagClient(offline=True)
        client_b = FlagClient(offline=True)
        client_a.override(GenAIFlags.PROMPT_V2_EXP, True)
        # client_b should not see client_a's overrides
        assert client_b.is_enabled(GenAIFlags.PROMPT_V2_EXP, ctx) is False
        client_a.close()
        client_b.close()

#!/usr/bin/env python3
# flag_audit.py
# Audit all GenAI feature flag references in the codebase
# against the canonical GenAIFlags registry.
# Use this to find: stale flags, undocumented flags, flags without rollout plans.
# Run: python flag_audit.py --src-dir src/

import ast
import os
import sys
import re
from pathlib import Path
from typing import Set

try:
    from feature_flags import GenAIFlags
    REGISTERED_KEYS = set(
        v for k, v in vars(GenAIFlags).items()
        if not k.startswith("_") and isinstance(v, str)
    )
except ImportError:
    print("Could not import GenAIFlags. Run from repo root with feature_flags.py present.")
    sys.exit(1)


def extract_flag_keys_from_file(path: Path) -> Set[str]:
    found = set()
    try:
        source = path.read_text()
    except Exception:
        return found
    # Match any string literal that looks like a GenAI flag key
    pattern = re.compile(r'"(genai\.[a-z0-9._-]+)"')
    for m in pattern.finditer(source):
        found.add(m.group(1))
    return found


def audit_flags(src_dir: str) -> None:
    src = Path(src_dir)
    all_used: Set[str] = set()
    file_usage: dict[str, Set[str]] = {}

    for py_file in src.rglob("*.py"):
        keys = extract_flag_keys_from_file(py_file)
        if keys:
            file_usage[str(py_file)] = keys
            all_used |= keys

    unregistered = all_used - REGISTERED_KEYS
    unused = REGISTERED_KEYS - all_used

    print(f"\n=== GenAI Feature Flag Audit ===")
    print(f"  Registered flags:   {len(REGISTERED_KEYS)}")
    print(f"  Used in codebase:   {len(all_used)}")
    print(f"  Unregistered used:  {len(unregistered)}")
    print(f"  Registered unused:  {len(unused)}")

    if unregistered:
        print("\nUNREGISTERED FLAG KEYS (add to GenAIFlags or remove):")
        for key in sorted(unregistered):
            files = [f for f, ks in file_usage.items() if key in ks]
            print(f"  {key}")
            for f in files:
                print(f"    in {f}")

    if unused:
        print("\nREGISTERED BUT UNUSED (candidate for cleanup):")
        for key in sorted(unused):
            print(f"  {key}")

    if not unregistered and not unused:
        print("\nAll flags are registered and in use. No action required.")
    else:
        sys.exit(1)


if __name__ == "__main__":
    import argparse
    parser = argparse.ArgumentParser()
    parser.add_argument("--src-dir", default="src")
    args = parser.parse_args()
    audit_flags(args.src_dir)
